import React from 'react';
import { Package, Zap, Check, X } from 'lucide-react';
import { useTranslation } from '../../i18n/context';

interface DualModelExplainerProps {
  credits: number;
  maxCredits: number;
  planName: string;
  currentPlan: 'free' | 'starter' | 'pro' | 'agence';
  onNavigate: (page: string) => void;
}

/* -- Plan data -- */
interface PlanDef {
  id: string;
  name: string;
  price: string;
  projects: string;
  projectsLabel: string;
  projectsSub: string;
  creditsLabel: string;
  featured: boolean;
  features: string[];
  missing: string[];
  cta: string;
}

const DualModelExplainer: React.FC<DualModelExplainerProps> = ({
  credits,
  maxCredits,
  planName,
  currentPlan,
  onNavigate,
}) => {
  const { t } = useTranslation();

  const percentage = maxCredits > 0 ? (credits / maxCredits) * 100 : 0;
  const barColor =
    percentage > 50
      ? 'from-emerald-500 to-emerald-400'
      : percentage > 25
        ? 'from-amber-500 to-amber-400'
        : 'from-red-500 to-red-400';

  const now = new Date();
  const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1);
  const renewalDays = Math.ceil((nextMonth.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));

  const normalizedPlan = currentPlan?.toLowerCase() || 'free';

  /* -- Plans (inside component to use t) -- */
  const plans: PlanDef[] = [
    {
      id: 'starter',
      name: 'STARTER',
      price: '29',
      projects: '1',
      projectsLabel: t.dashboard.project,
      projectsSub: t.dashboard.oneProjectOneSite,
      creditsLabel: `50 ${t.dashboard.creditsMonth}`,
      featured: false,
      features: [
        t.dashboard.starterFeature1,
        t.dashboard.starterFeature2,
        t.dashboard.starterFeature3,
      ],
      missing: [
        t.dashboard.starterMissing1,
        t.dashboard.starterMissing2,
        t.dashboard.starterMissing3,
        t.dashboard.starterMissing4,
      ],
      cta: t.dashboard.start,
    },
    {
      id: 'pro',
      name: 'PRO',
      price: '79',
      projects: '5',
      projectsLabel: t.dashboard.projects,
      projectsSub: t.dashboard.oneProjectOneSite,
      creditsLabel: `200 ${t.dashboard.creditsMonth}`,
      featured: true,
      features: [
        t.dashboard.proFeature1,
        t.dashboard.proFeature2,
        t.dashboard.proFeature3,
        t.dashboard.proFeature4,
        t.dashboard.proFeature5,
        t.dashboard.proFeature6,
      ],
      missing: [
        t.dashboard.proMissing1,
        t.dashboard.proMissing2,
      ],
      cta: `${t.dashboard.choosePro} \u2192`,
    },
    {
      id: 'agence',
      name: 'AGENCE',
      price: '199',
      projects: '\u221E',
      projectsLabel: t.dashboard.unlimitedProjects,
      projectsSub: t.dashboard.oneProjectOneSite,
      creditsLabel: `1 000 ${t.dashboard.creditsMonth}`,
      featured: false,
      features: [
        t.dashboard.agencyFeature1,
        t.dashboard.agencyFeature2,
        t.dashboard.agencyFeature3,
        t.dashboard.agencyFeature4,
        t.dashboard.agencyFeature5,
        t.dashboard.agencyFeature6,
      ],
      missing: [],
      cta: t.dashboard.contactUs,
    },
  ];

  /* -- Credit action cards (inside component to use t) -- */
  const creditActions = [
    { icon: '\u{1F50D}', label: t.dashboard.audit, cost: '1 \u26A1' },
    { icon: '\u{1F6E0}\uFE0F', label: t.dashboard.solution, cost: '1 \u26A1' },
    { icon: '\u{1F4CA}', label: t.dashboard.citationCheck, cost: '2 \u26A1' },
    { icon: '\u{1F30D}', label: t.dashboard.language, cost: '3 \u26A1' },
  ];

  /* -- Credit detail rows (inside component to use t) -- */
  const creditRows = [
    { icon: '\u{1F50D}', label: t.dashboard.fullAudit, cost: '1 \u26A1' },
    { icon: '\u{1F6E0}\uFE0F', label: t.dashboard.unlockSolution, cost: '1 \u26A1' },
    { icon: '\u{1F4CA}', label: t.dashboard.citationCheck, cost: '2 \u26A1' },
    { icon: '\u{1F30D}', label: t.dashboard.multilingualPerLang, cost: '3 \u26A1' },
    { icon: '\u{1F504}', label: t.dashboard.reScanComparison, cost: '1 \u26A1' },
    { icon: '\u{1F4DD}', label: t.dashboard.aiContentGeneration, cost: '2 \u26A1' },
  ];

  /* -- Included in subscription items -- */
  const includedItems = [
    t.dashboard.includedPlatformAccess,
    t.dashboard.includedMonthlyCredits,
    t.dashboard.includedAuditCriteria,
    t.dashboard.includedSolutions,
    t.dashboard.includedDashboard,
  ];

  return (
    <div className="space-y-10">
      {/* === A. LES DEUX MODELES COTE A COTE === */}
      <div>
        <h2 className="text-xl font-semibold text-white">{t.dashboard.howItWorks}</h2>
        <p className="text-[14px] text-zinc-400 mt-1">
          {t.dashboard.twoMechanisms}
        </p>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-5 mt-6">
          {/* -- Card gauche : L'abonnement -- */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-7 relative overflow-hidden">
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-blue-500/10 border border-blue-500/20">
              <Package className="w-4 h-4 text-blue-400" />
              <span className="text-[13px] font-semibold text-blue-400 uppercase tracking-wider">{t.dashboard.subscription}</span>
            </div>

            <h3 className="text-xl font-semibold text-white mt-5">{t.dashboard.subscriptionDesc}</h3>
            <p className="text-[15px] text-zinc-400 mt-3 leading-relaxed">
              {t.dashboard.subscriptionExplain}
            </p>

            <div className="mt-5 space-y-3">
              {[
                t.dashboard.oneProject,
                t.dashboard.planDetermines,
                t.dashboard.scaleUp,
              ].map((text, i) => (
                <div key={i} className="flex items-start gap-3">
                  <div className="w-6 h-6 rounded-full bg-blue-500/10 flex items-center justify-center text-[12px] font-bold text-blue-400 flex-shrink-0">
                    {i + 1}
                  </div>
                  <span className="text-[14px] text-zinc-300">{text}</span>
                </div>
              ))}
            </div>

            <div className="mt-6 p-4 rounded-xl bg-white/[0.02] border border-white/[0.04] flex items-start gap-3">
              <span className="text-lg">{'\u{1F4F1}'}</span>
              <p className="text-[13px] text-zinc-400 italic leading-relaxed">
                {t.dashboard.mobileAnalogy}
              </p>
            </div>

            <div className="mt-6">
              <p className="text-[12px] uppercase tracking-wider text-zinc-600 font-medium mb-3">
                {t.dashboard.includedInSubscription}
              </p>
              <div className="space-y-2">
                {includedItems.map((item, i) => (
                  <div key={i} className="flex items-center gap-2.5">
                    <Check className="w-4 h-4 text-emerald-500 flex-shrink-0" />
                    <span className="text-[14px] text-zinc-400">{item}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* -- Card droite : Les credits GTO -- */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-7 relative overflow-hidden">
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-amber-500/10 border border-amber-500/20">
              <Zap className="w-4 h-4 text-amber-400" />
              <span className="text-[13px] font-semibold text-amber-400 uppercase tracking-wider">{t.dashboard.creditsGTO}</span>
            </div>

            <h3 className="text-xl font-semibold text-white mt-5">{t.dashboard.creditsFuel}</h3>
            <p className="text-[15px] text-zinc-400 mt-3 leading-relaxed">
              {t.dashboard.creditsExplain}
            </p>

            <div className="mt-5 space-y-3">
              {[
                t.dashboard.creditsQuota,
                t.dashboard.creditsCost,
                t.dashboard.creditsTopUp,
              ].map((text, i) => (
                <div key={i} className="flex items-start gap-3">
                  <div className="w-6 h-6 rounded-full bg-amber-500/10 flex items-center justify-center text-[12px] font-bold text-amber-400 flex-shrink-0">
                    {i + 1}
                  </div>
                  <span className="text-[14px] text-zinc-300">{text}</span>
                </div>
              ))}
            </div>

            <div className="mt-6 p-4 rounded-xl bg-white/[0.02] border border-white/[0.04] flex items-start gap-3">
              <span className="text-lg">{'\u26FD'}</span>
              <p className="text-[13px] text-zinc-400 italic leading-relaxed">
                {t.dashboard.gasAnalogy}
              </p>
            </div>

            <div className="mt-6">
              <p className="text-[12px] uppercase tracking-wider text-zinc-600 font-medium mb-3">
                {t.dashboard.availableActions}
              </p>
              <div className="space-y-2">
                {creditRows.map((row, i) => (
                  <div key={i} className="flex items-center justify-between">
                    <div className="flex items-center gap-2.5">
                      <span className="text-zinc-500">{row.icon}</span>
                      <span className="text-[14px] text-zinc-400">{row.label}</span>
                    </div>
                    <span className="text-[14px] font-mono text-amber-400">{row.cost}</span>
                  </div>
                ))}
              </div>

              <div className="mt-4 flex items-start gap-2 bg-amber-500/[0.05] border border-amber-500/[0.1] rounded-lg p-3">
                <span>{'\u{1F4A1}'}</span>
                <span className="text-[13px] text-zinc-400">
                  {t.dashboard.packSolutions}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* === B. L'ABONNEMENT EN DETAIL === */}
      <div>
        <div className="flex items-center gap-4 mt-10 mb-2">
          <div className="flex-1 h-px bg-white/[0.06]" />
          <span className="text-[12px] uppercase tracking-wider text-zinc-600 font-medium">{t.dashboard.choosePlan}</span>
          <div className="flex-1 h-px bg-white/[0.06]" />
        </div>
        <p className="text-center text-[14px] text-zinc-400 mt-2">
          {t.dashboard.morePlans}
        </p>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-5 mt-8">
          {plans.map((plan) => {
            const isCurrent = normalizedPlan === plan.id;
            const borderClass = plan.featured
              ? 'border-blue-500/20 ring-1 ring-blue-500/10'
              : 'border-white/[0.06]';

            return (
              <div
                key={plan.id}
                className={`relative bg-white/[0.03] border ${borderClass} rounded-2xl p-7 flex flex-col`}
              >
                {plan.featured && (
                  <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-blue-500 text-white text-[11px] font-bold uppercase tracking-wider px-3 py-1 rounded-full z-10">
                    {t.dashboard.popular}
                  </span>
                )}

                <p className={`text-[13px] uppercase tracking-wider font-medium ${plan.featured ? 'text-blue-400' : 'text-zinc-400'}`}>
                  {plan.name}
                </p>

                <div className="mt-3">
                  <span className="text-4xl font-bold text-white tracking-tight">{plan.price}</span>
                  <span className="text-lg text-zinc-500 ml-0.5">&euro;</span>
                  <span className="text-[14px] text-zinc-500 ml-1">{t.dashboard.month}</span>
                </div>

                {/* Pivot central -- nombre de projets */}
                <div className="mt-5 py-4 border-y border-white/[0.06] text-center">
                  <span className={`text-3xl font-bold ${plan.featured ? 'text-blue-400' : 'text-white'}`}>
                    {plan.projects}
                  </span>
                  <p className="text-[14px] text-zinc-400 mt-1">{plan.projectsLabel}</p>
                  <p className="text-[12px] text-zinc-600 mt-0.5">{plan.projectsSub}</p>
                </div>

                {/* Credits inclus */}
                <div className="mt-5 flex items-center gap-2">
                  <Zap className="w-4 h-4 text-amber-400" />
                  <span className="text-[15px] text-white font-semibold">{plan.creditsLabel}</span>
                </div>

                {/* Features */}
                <div className="mt-5 flex-1 space-y-2.5">
                  {plan.features.map((feat, i) => (
                    <div key={i} className="flex items-start gap-2">
                      <Check className="w-4 h-4 text-emerald-500 flex-shrink-0 mt-0.5" />
                      <span className="text-[14px] text-zinc-400">{feat}</span>
                    </div>
                  ))}
                  {plan.missing.map((feat, i) => (
                    <div key={`m-${i}`} className="flex items-start gap-2">
                      <X className="w-4 h-4 text-zinc-700 flex-shrink-0 mt-0.5" />
                      <span className="text-[14px] text-zinc-600">{feat}</span>
                    </div>
                  ))}
                </div>

                {/* CTA */}
                <div className="mt-6">
                  {isCurrent ? (
                    <div className="w-full bg-white/[0.06] text-zinc-500 rounded-lg py-2.5 text-center text-[14px] font-medium cursor-default">
                      {t.dashboard.yourCurrentPlan} {'\u2713'}
                    </div>
                  ) : plan.featured ? (
                    <button
                      onClick={() => onNavigate('plan')}
                      className="w-full bg-white text-black font-semibold px-6 py-2.5 rounded-lg text-[14px] hover:bg-zinc-200 transition-all duration-150"
                    >
                      {plan.cta}
                    </button>
                  ) : (
                    <button
                      onClick={() => onNavigate('plan')}
                      className="w-full bg-white/[0.06] text-zinc-300 font-medium border border-white/[0.08] px-6 py-2.5 rounded-lg text-[14px] hover:bg-white/[0.1] hover:text-white transition-all duration-150"
                    >
                      {plan.cta}
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        <div className="mt-4 text-center text-[13px] text-zinc-500">
          {t.dashboard.currentPlan} :{' '}
          <span className="text-blue-400 font-medium">{planName || t.dashboard.free}</span>
          {' \u00B7 '}
          <button
            onClick={() => onNavigate('plan')}
            className="text-blue-400 hover:text-blue-300 cursor-pointer"
          >
            {t.dashboard.manageSub} &rarr;
          </button>
        </div>
      </div>

      {/* === C. LES CREDITS EN DETAIL === */}
      <div>
        <div className="flex items-center gap-4 mt-10 mb-2">
          <div className="flex-1 h-px bg-white/[0.06]" />
          <span className="text-[12px] uppercase tracking-wider text-zinc-600 font-medium">{t.dashboard.yourCredits}</span>
          <div className="flex-1 h-px bg-white/[0.06]" />
        </div>

        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-7 mt-6">
          {/* Header */}
          <div className="flex justify-between items-center">
            <h3 className="text-white font-semibold">{t.dashboard.creditReserve}</h3>
            <div className="flex items-center gap-2">
              <Zap className="w-5 h-5 text-amber-400" />
              <span className="text-2xl font-bold text-white font-mono">{credits}</span>
              <span className="text-lg text-zinc-500">/ {maxCredits}</span>
            </div>
          </div>

          {/* Progress bar */}
          <div className="mt-5">
            <div className="h-3 w-full rounded-full bg-white/[0.06]">
              <div
                className={`h-3 rounded-full bg-gradient-to-r ${barColor} transition-all duration-700 ease-out`}
                style={{ width: `${percentage}%` }}
              />
            </div>
            <div className="flex justify-between mt-2">
              <span className="text-[12px] text-zinc-500">{t.dashboard.used} : {maxCredits - credits}</span>
              <span className="text-[12px] text-zinc-500">{t.dashboard.remaining} : {credits}</span>
            </div>
          </div>

          {/* 4 mini-cards */}
          <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-3">
            {creditActions.map((action, i) => (
              <div
                key={i}
                className="bg-white/[0.04] border border-white/[0.06] rounded-xl p-4 text-center hover:bg-white/[0.06] transition-all duration-150"
              >
                <div className="text-lg">{action.icon}</div>
                <div className="text-[13px] text-zinc-400 mt-2">{action.label}</div>
                <div className="text-lg font-bold font-mono text-amber-400 mt-1">{action.cost}</div>
              </div>
            ))}
          </div>

          {/* Pack tip */}
          <div className="mt-5 flex items-center gap-3 bg-emerald-500/[0.05] border border-emerald-500/[0.1] rounded-xl p-4">
            <span className="bg-emerald-500/10 text-emerald-400 text-[11px] font-bold px-2 py-0.5 rounded">
              -30%
            </span>
            <span className="text-[14px] text-zinc-400">
              {t.dashboard.packSolutionsCredits}
            </span>
          </div>

          {/* Recharge CTA */}
          <div className="mt-6 flex items-center justify-between">
            <span className="text-[13px] text-zinc-500">
              {t.dashboard.renewalIn} {renewalDays} {t.dashboard.days}
            </span>
            {percentage < 25 ? (
              <button
                onClick={() => onNavigate('recharge')}
                className="bg-white text-black font-semibold px-5 py-2 rounded-lg text-[13px] hover:bg-zinc-200 transition-all duration-150"
              >
                {t.dashboard.recharge} {'\u26A1'}
              </button>
            ) : (
              <button
                onClick={() => onNavigate('recharge')}
                className="bg-white/[0.06] text-zinc-300 font-medium border border-white/[0.08] px-5 py-2 rounded-lg text-[13px] hover:bg-white/[0.1] hover:text-white transition-all duration-150"
              >
                {t.dashboard.buyCredits} &rarr;
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DualModelExplainer;
